Create a new file packages/service-core/src/utils/transaction.ts with the withServiceTransaction function. This wraps @repo/db's withTransaction to create a properly initialized ServiceContext with a transaction client and empty hookState.

Implementation:
```typescript
import { sql } from 'drizzle-orm';
import { withTransaction } from '@repo/db';
import type { ServiceContext } from '../types';

export async function withServiceTransaction<T>(
  fn: (ctx: ServiceContext) => Promise<T>,
  baseCtx?: Partial<ServiceContext>,
  options?: { timeoutMs?: number }
): Promise<T> {
  return withTransaction(async (tx) => {
    const timeout = options?.timeoutMs ?? 30_000;
    await tx.execute(sql`SET LOCAL statement_timeout = ${sql.raw(String(timeout))}`);
    const ctx: ServiceContext = {
      ...baseCtx,
      tx,
      hookState: baseCtx?.hookState ?? {},
    };
    return fn(ctx);
  });
}
```

NOTE: SET LOCAL scopes the timeout to the current transaction only (auto-resets on commit/rollback). Using sql.raw() is safe here because timeout is always a number, never user input.

